use std::collections::HashSet;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let text1 = "This is the first document content.";
    let text2 = "This is the first document content. ";
    let text3 = "Totally different stuff";

    let mut hashes: HashSet<u64> = HashSet::new();
    hashes.insert(calculate_rolling_hash(text1));
    hashes.insert(calculate_rolling_hash(text2));
    hashes.insert(calculate_rolling_hash(text3));

    println!("Hashes generated for three texts.");

    let check_text = "This is the first document content.";
    let hash_to_check = calculate_rolling_hash(check_text);

    if hashes.contains(&hash_to_check) {
        println!("The text provided matches a previously seen fingerprint.");
    } else {
        println!("The text provided is new.");
    }

    Ok(())
}

fn calculate_rolling_hash(s: &str) -> u64 {
    let mut hash = 0u64;
    for byte in s.bytes() {
        hash = hash.wrapping_mul(31).wrapping_add(byte as u64);
    }
    hash
}

use std::collections::HashSet;

struct Rect {
    x1: i32,
    y1: i32,
    x2: i32,
    y2: i32,
}

impl Rect {
    fn new(x1: i32, y1: i32, x2: i32, y2: i32) -> Self {
        Rect { x1, y1, x2: std::cmp::max(x1, x2), y2: std::cmp::max(y1, y2) }
    }

    fn overlaps(&self, other: &Self) -> bool {
        let x_overlap = self.x1.min(self.x2) <= other.x1.min(other.x2)
            && self.x1.max(self.x2) >= other.x1.max(other.x2);

        let y_overlap = self.y1.min(self.y2) <= other.y1.min(other.y2)
            && self.y1.max(self.y2) >= other.y1.max(other.y2);

        x_overlap && y_overlap
    }
}

use std::collections::HashMap;
use std::fs;
use std::path::Path;
use std::time::{SystemTime, Duration};

#[derive(Debug)]
pub struct FileSetHasher {
    file_map: HashMap<String, u64>,
}

impl FileSetHasher {
    pub fn new() -> Self {
        FileSetHasher { file_map: HashMap::new() }
    }

    pub fn add_file(&mut self, path: &Path) -> Result<(), std::io::Error> {
        let metadata = fs::metadata(path)?;
        let modified_time = metadata.modified()?;
        let duration = modified_time.elapsed().map_err(|e| std::io::Error::new(std::io::ErrorKind::Other, e));
        let hash_value = duration?.as_nanos() as u64;
        self.file_map.insert(path.to_string_lossy().into_owned(), hash_value);
        Ok(())
    }

    pub fn calculate_combined_hash(&self) -> u64 {
        let mut combined_hash: u64 = 0;
        for (_, hash) in &self.file_map {
            combined_hash = combined_hash.wrapping_add(*hash);
        }
        combined_hash
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut hasher = FileSetHasher::new();
    let build_dir = Path::new("src/assets");

    if !build_dir.exists() {
        println!("Build directory not found, creating dummy files for test.");
        fs::create_dir_all(build_dir)?;
        fs::write("src/assets/index.js", "const x = 1;")?;
        fs::write("src/assets/styles.css", "body { color: red; }")?;
    }

    hasher.add_file(&Path::new("src/assets/index.js"))?;
    hasher.add_file(&Path::new("src/assets/styles.css"))?;

    let final_hash = hasher.calculate_combined_hash();

    println!("Successfully hashed the file set.");
    println!("Combined Version Hash: {}", final_hash);

    Ok(())
}

use std::collections::HashSet;

struct StringHasher {
    base: u64,
    modulus: u64,
}

impl StringHasher {
    fn new(base: u64, modulus: u64) -> Self {
        StringHasher { base, modulus }
    }

    fn hash(&self, text: &str) -> u64 {
        let mut hash_value = 0;
        for byte in text.bytes() {
            let char_val = (byte as u64);
            hash_value = ((hash_value * self.base) % self.modulus)
                .wrapping_add(char_val % self.modulus);
            hash_value = hash_value % self.modulus;
        }
        hash_value
    }
}

fn main() {
    let hasher = StringHasher::new(31, 1_000_000_007);
    let mut seen_fingerprints: HashSet<u64> = std::collections::HashSet::new();

    let data_strings = vec![
        "user_id_982",
        "session_token_abc",
        "user_id_1001",
        "data_record_xyz"
    ];

    for s in data_strings {
        let fingerprint = hasher.hash(s);
        seen_fingerprints.insert(fingerprint);
    }

    println!("Successfully hashed and stored {} unique fingerprints.", seen_fingerprints.len());
}

use std::collections::HashMap;
use std::hash::{Hash, Hasher};
use std::io::Cursor;

struct FeatureStore {
    hashes: HashMap<String, u64>,
}

impl FeatureStore {
    fn new() -> Self {
        FeatureStore { hashes: HashMap::new() }
    }

    fn compute_and_store_hash(&mut self, key1: &str, separator: &str, key2: &str) -> u64 {
        let combined_key = format!("{}{}{}", key1, separator, key2);
        let mut hasher = std::collections::hash_map::DefaultHasher::new();
        combined_key.hash(&mut hasher);
        let hash_value = hasher.finish();
        self.hashes.insert(combined_key, hash_value);
        hash_value
    }
}

fn main() {
    let mut store = FeatureStore::new();
    let h1 = store.compute_and_store_hash("user", "|", "profile");
    let h2 = store.compute_and_store_hash("item", "|", "product_id_456");
    println!("Stored hash 1: {}", h1);
    println!("Stored hash 2: {}", h2);
}
